var e=[{id:`L7_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`으음…….`,JPN:`うーん……`,ENG:`Mmm...`,TWN:`唔……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_DESPAIR`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`으윽! 머리야…… 아까 폭발 때문에…… 기절한 건가?`,JPN:`ううっ！　頭痛い……さっきの爆発で……気絶してたのか？`,ENG:`Urgh! My head... Did I faint because of the explosion...?`,TWN:`呃！我的頭……我是因為剛剛的爆炸……才暈過去的嗎？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`엇!? 우리 부스가…… 완전히 무너졌잖아!?`,JPN:`えっ！？　僕たちのブースが……完全に崩れてる！？`,ENG:`Huh?! Our booth... It’s completely destroyed!`,TWN:`唔！？我們的攤位……根本變成廢墟啦！？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`다들 그렇게 열심히 준비했는데…….`,JPN:`みんなであんなに一生懸命準備したのに……`,ENG:`After all the work we put in...`,TWN:`我們準備得那麼辛苦……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_DESPAIR`},C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`잠깐, 누나들은 어디간거지……? 갑자기 행사장은 왜 폭발한 거고……?`,JPN:`待てよ、みんなはどこ行ったんだろう……？　会場はなんで突然爆発したんだ……？`,ENG:`Wait, where are the girls...? Why did the convention center explode, all of a sudden...?`,TWN:`等一下，姊姊她們呢……？展場為什麼會突然爆炸……？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`음……?`,JPN:`うん……？`,ENG:`Mm...?`,TWN:`嗯……？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_SURPRISE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`아, 아아아앗!? 자, 잠깐만! 어, 어디갔지!?`,JPN:`あ、ああああっ！？　あ、あれ？　ど、どこにいったんだろう！？`,ENG:`A-Ahhhhh?! W-wait! W-where did it go?!`,TWN:`啊啊啊啊啊！？怎…怎麼不見了！跑…跑哪去了！？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,text:{KOREA:`내 마스크……! 내 샐러리맨X 마스크……!`,JPN:`僕のマスク……！　僕のサラリーマンXのマスク……！`,ENG:`My mask...! My Salaryman X mask...!`,TWN:`我的面具……！我的上班族X面具呢……！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`CHEOLSU_NPC_GAMECIRCLE_CHILD`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`……이쪽은 대충 정리됐나?`,JPN:`……こっちはだいたい片付いたか？`,ENG:`...All clear over here.`,TWN:`……這裡處理得差不多了唄？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`타이밍도 윽수로 나쁘네. 하필 코미페 날에 사고가 터지는 건 뭔데?`,JPN:`タイミング悪すぎやで。コミフェの日に事故なんてな。`,ENG:`Such bad timing. Why did it have to be the day of Comic Festival, out of all days?`,TWN:`還真會挑時間，偏偏挑在動漫展的時候出事？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`DAIN_GAMECIRCLE_NULL_NULL`,text:{KOREA:`리네야! 사람들도 대부분 대피했어. 선생님도 곧 지원을 보내신데!`,JPN:`マリちゃん！　みんなほとんど避難したよ。先生ももうすぐ応援を送ってくれるって！`,ENG:`Rinae! We’re almost done with the evacuation. Teach is sending us support!`,TWN:`璃奈！人差不多都離開了，老師也說會派支援過來！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`좋네, 이제 쌤이 보낸 지원이 올 때까지 마무리만 하고 있음 되나?`,JPN:`良かったわ、ここからは先生が送った応援が来るまでに終わらせればええか？`,ENG:`Good, so all we gotta do is to stay low until help comes?`,TWN:`太好了，那就整理一下，等老師的支援抵達唄？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`……아직이야.`,JPN:`……まだ。`,ENG:`...Not so fast.`,TWN:`……還沒結束。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`부상하고 있어…… 뭔가가!`,JPN:`浮上してる……何かが！`,ENG:`It’s coming... something bad!`,TWN:`有東西……接近中！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`에엥!? 뭐가 또 온다고!?`,JPN:`ええっ！？　また何かが来るやて！？`,ENG:`Eh?! There’s more of ‘em?`,TWN:`啥！？又有啥東東接近中！？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};